// Debounce is a SUBFLOW — not a constraint on the triggering node.
// A constraint on NODE A1: 'handle debounce' is documentation.
// The subflow is enforcement.

// SUBFLOW-02D: QuestionnaireDebounce (three nodes)
// D1 — Debounce Key Check: is this submission within the window?
// D2 — Existing Profile Return: return current profile without reprocessing (READ-ONLY)
// D3 — Stale Event Discard Record: write PERSISTENT audit record (not a log line)

// D1 key check:
const debounceKey = `debounce:${tenantId}:${userId}`;  // COMPOUND — never userId alone
const windowSeconds = await this.freedomConfig.get('flow02_debounce_window_seconds') ?? 300;
// Cross-tenant isolation: Tenant A's rapid edits cannot debounce Tenant B's user

// D3 discard record (persistent — not application logs):
await this.db.storeDocument('xiigen-debounce-discards', {
  userId, questionnaireId,
  discardedAt: new Date().toISOString(),
  reason: 'DEBOUNCE_ACTIVE',
  windowSeconds,
  tenantId,
  connectionType: 'FLOW_SCOPED', knowledgeScope: 'PRIVATE',
}, `discard-${questionnaireId}`);
// ↑ Answers: 'why was my profile update ignored?' — without this record, there is no answer
